function [scnAdr logNam] = fTrexLgFlNmV01(scnNmb)  %function header%%%%%%%%%% Function fTrexLgFlNmV01.m %%%%%%%%%%% Function Trex Log File Name, ver.1% Kei Nakamura% Created on Saturday, June 9th 2007.% Modified on Thursday, June 21st 2007.%% function [scnAdr logNam] = fTrexLgFlNmV01(scnNmb)% returns the name of the log files% scnNmb: Scan number% scnAdr: address for scan% logNam% 1: 100tw log% 2: 100tw info file% 3: magnetic spc log% 4: spot log% 5: easylog% 6: beam on offaif scnNmb<10    scnS3 = ['00',num2str(scnNmb)]; % scan string with 001 format    scnAdr = strcat('Scan00',num2str(scnNmb));    logNam{1} = strcat('ScanDataScan00',num2str(scnNmb),'.txt');    logNam{2} = strcat('ScanInfoScan00',num2str(scnNmb),'.txt');    elseif scnNmb<100    scnS3 = ['0',num2str(scnNmb)]; % scan string with 001 format    scnAdr = strcat('Scan0',num2str(scnNmb));    logNam{1} = strcat('ScanDataScan0',num2str(scnNmb),'.txt');    logNam{2} = strcat('ScanInfoScan0',num2str(scnNmb),'.txt');else    scnS3 = num2str(scnNmb); % scan string with 001 format    scnAdr = strcat('Scan',num2str(scnNmb));    logNam{1} = strcat('ScanDataScan',num2str(scnNmb),'.txt');    logNam{2} = strcat('ScanInfoScan',num2str(scnNmb),'.txt');endlogNam{3} = strcat('scan',num2str(scnNmb),'mSpctLog.txt');logNam{4} = strcat('scan',num2str(scnNmb),'spt.txt');logNam{5} = strcat('scan',num2str(scnNmb),'easyLog.txt');logNam{6} = strcat('scan',num2str(scnNmb),'beam.txt');logNam{7} = strcat('scan',num2str(scnNmb),'Delay.txt');logNam{8} = strcat('osmLog.txt');logNam{9} = ['scan',num2str(scnNmb),'phosLog.txt'];logNam{10} = ['scan',scnS3,'ICT.txt'];logNam{11} = ['scan',num2str(scnNmb),'laserLog.txt'];logNam{12} = ['Scan',scnS3,'_Phasics_ML.txt'];
